    s = s.strip().strip(".'\"")
    if re.search(r'\d', s):
        return None
    if len(s) < 2:
        return None
    if len(s) == 2 and s.isupper():
        return None
    if s.lower().startswith(('this', 'offers', 'making', 'located')):
        return None
    return s

cat_map = {}
