    seen = set()
    for raw in toks:
        parts = re.split(r',|\band\b|;|\\\\|/', raw)
        for p in parts:
            c = clean_token(p)
            if c:
                c = c.strip()
                if len(c) > 60:
                    continue
                seen.add(c)
    for c in seen:
        cat_map.setdefault(c, set()).add(bref)

cat_counts = {c: len(s) for c, s in cat_map.items()}
if not cat_counts:
    top_category = 'Unknown'
    top_bizrefs = []
else:
    top_category = max(cat_counts.items(), key=lambda x: x[1])[0]
